mapper.select:
SELECT r.*, t.name as type_name
FROM t_room r
LEFT JOIN t_room_type t ON r.type_id = t.id
WHERE r.status = 'idle'

    AND r.type_id = #{typeId}

AND r.id NOT IN (
    SELECT o.room_id FROM t_order o
    WHERE o.status IN ('pending', 'checkedIn')
      AND o.check_in_time < #{endTime}
      AND o.expected_check_out_time > #{startTime}
)
ORDER BY r.floor, r.room_no
